head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"intervalCount" : 5,
	},
	"radDisplayData" : [
		{"name" : "일별", "tooltip" : "전일기준 실시간 한전 데이터 조회"},
		{"name" : "월별", "tooltip" : "한전 고지서 데이터 조회"}
	],
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCN2000000", {"initScreenCallback" : scwin.searchDatas});
};

	/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();

	//ecsLib.setChartResizeObserver(this);
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("strtDtD", utilLib.addDay(utilLib.getCurrentDate("yyyyMMdd"), -1));
	dmaSearchParam.set("strtDtM", utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -1));
	dmaSearchParam.set("stdrBasinCd", "");
	dmaSearchParam.set("cmprBasinCd", "");
};

/**
 * 라디오버튼별 툴팁을 설정한다.
 * @param
 * @return
 */
scwin.setSbxDisplayTooltip = function(label, index) {
	return scwin.initData.radDisplayData.find(obj => obj.name == label).tooltip;
};

/**
 * 조회조건에 맞게 chartData, grdData를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var cnd = radMdBy.getValue();
	var ecsChrgDeptId = dmaSearchParam.get("stdrBplcCd");
	var cmprEcsChrgDeptId = dmaSearchParam.get("cmprBplcCd");

	if (cnd == "D") {
		var strtDate = dmaSearchParam.get("strtDtD");
		var endDt = strtDate;

		if (String(strtDate).length != 8) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		} else if (ecsChrgDeptId == "" || cmprEcsChrgDeptId == "") {
			alert("사업장을 선택하세요.");
			return;
		} else if (ecsChrgDeptId == cmprEcsChrgDeptId) {
			alert("같은 사업장을 선택할 수 없습니다.");
			return;
		}
	} else {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDt = strtDate;

		if (String(strtDate).length != 6) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
		} else if (ecsChrgDeptId == "" || cmprEcsChrgDeptId == "") {
			alert("사업장을 선택하세요.");
			return;
		} else if (ecsChrgDeptId == cmprEcsChrgDeptId) {
			alert("같은 사업장을 선택할 수 없습니다.");
			return;
		}
	}
	cnd = cnd == "M" ? "mnby" : "daly";

	// 라디오버튼 선택에 따라 그리드 타이틀을 변경한다_240104
	var radMdByNm = radMdBy.getText();
	spnSubTitle.setLabel("소비전력 증감률 비교" + "(" + radMdByNm + ")");

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDt}`;
	queryString += `&cnd=${cnd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
	queryString += `&cmprEcsChrgDeptId=${cmprEcsChrgDeptId}`;

	// 소비전력 증감률 비교 그리드 데이터 조회
	var option = {
		action : "cn/pwcspcmprsttus/retrieve-pwcsp-cmpr-sttus.do"
			+ queryString,
		method : "get",
		resData : dltEpbuSttusList,
		success : "scwin.inqireGrdCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);

	// 기준부서 차트 데이터 조회
	var option = {
		action : "cn/pwcspcmprsttus/retrieve-pwcsp-cmpr-sttus-chart.do"
			+ queryString,
		method : "get",
		resData : bplcChartList,
		success : "scwin.inqireChartCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 GrdCallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireGrdCallback = function() {
	spnTotalRow.setValue(dltEpbuSttusList.getRowCount());
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		grdEpbuSttusList.setHeaderValue("hThsmonCnsmpElteng", dmaSearchParam.get("strtDtD").substr(0, 4) + "." + dmaSearchParam.get("strtDtD").substr(4, 2) + "." + dmaSearchParam.get("strtDtD").substr(6, 2) +" 소비전력(kWh)");
		grdEpbuSttusList.setHeaderValue("hPreYyMtCnsmpElteng", dmaSearchParam.get("strtDtD").substr(0, 4) + "." + dmaSearchParam.get("strtDtD").substr(4, 2) + "." +  (Number(dmaSearchParam.get("strtDtD").substr(6, 2)) - 1) + " 소비전력(kWh)");
		grdEpbuSttusList.setHeaderValue("hPrvyySammVersusPwcspDcrsRt", "전일대비 소비전력 증감률(%)");
		grdEpbuSttusList.setHeaderValue("hWntyPrvyySammVersusCnsmpRedcnRtRnk", "전일대비 소비증감률 전국 순위");
		grdEpbuSttusList.setHeaderValue("hBasinPrvyySammVersusCnsmpRedcnRtRnk", "전일대비 소비증감률 유역 순위");
	} else {
		grdEpbuSttusList.setHeaderValue("hThsmonCnsmpElteng", dmaSearchParam.get("strtDtM").substr(0, 4) + "." + dmaSearchParam.get("strtDtM").substr(4, 2) + " 소비전력(kWh)");
		grdEpbuSttusList.setHeaderValue("hPreYyMtCnsmpElteng", (Number(dmaSearchParam.get("strtDtM").substr(0, 4)) - 1) + "." + dmaSearchParam.get("strtDtM").substr(4, 2) + " 소비전력(kWh)");
		grdEpbuSttusList.setHeaderValue("hPrvyySammVersusPwcspDcrsRt", "전년 동월대비 소비전력 증감률(%)");
		grdEpbuSttusList.setHeaderValue("hWntyPrvyySammVersusCnsmpRedcnRtRnk", "전년 동월대비 소비증감률 전국 순위");
		grdEpbuSttusList.setHeaderValue("hBasinPrvyySammVersusCnsmpRedcnRtRnk", "전년 동월대비 소비증감률 유역 순위");
	}
};

/**
 * 기준유역 조회박스 선택 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbStdrBasin_onviewchange = function(info) {
	dmaSearchParam.set("stdrBasinCd", info.newValue);

	var queryString = "?ecsBasinDivCd=" + info.newValue;

	var option = {
		action : "zz/cmmn/retrieve-cnsmp-sttus-cnd-kepco-dept.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition2,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 기준부서 조회박스 선택 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbStdrBplc_onviewchange = function(info) {
	dmaSearchParam.set("stdrBplcCd", info.newValue);
};

/**
 * 비교유역 조회박스 선택 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbCmprBasin_onviewchange = function(info) {
	dmaSearchParam.set("cmprBasinCd", info.newValue);

	var queryString = "?ecsBasinDivCd=" + info.newValue;

	var option = {
		action : "zz/cmmn/retrieve-cnsmp-sttus-cnd-kepco-dept.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition4,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 비교부서 조회박스 선택 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbCmprBplc_onviewchange = function(info) {
	dmaSearchParam.set("cmprBplcCd", info.newValue);
};

/**
 * 라디오버튼 선택에 따라 조회날짜를 변경한다.
 * @param
 * @return
 */
scwin.radMdBy_onviewchange = function(info) {
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		grpCalDNm.setStyle("display", "");
		grpCalDBox.setStyle("display", "");
		grpCalMNm.setStyle("display", "none");
		grpCalMBox.setStyle("display", "none");
	} else if (cnd == "M") {
		grpCalDNm.setStyle("display", "none");
		grpCalDBox.setStyle("display", "none");
		grpCalMNm.setStyle("display", "");
		grpCalMBox.setStyle("display", "");
	} else {
		return;
	}
};

/**
 * 그리드 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplZeroFrmt = function(value) {
	if (value == "-") {
		return value;
	}
	return ecsLib.dsplZeroFrmt(value, 1);
};

//============================================================================================
// 차트
//============================================================================================
 /**
 * 기준부서 차트 생성
 */
scwin.inqireChartCallback = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandler";
	rMateChartH5.create($p.id + "ChartStdr", grpChartStdr.getID(), chartVars, "100%", "100%");

	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandler";
	rMateChartH5.create($p.id + "ChartCmpr", grpChartCmpr.getID(), chartVars, "100%", "100%");
};

/**
 * 부서 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandler = function(id) {
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		var date = new Date(dmaSearchParam.get("strtDtD").substr(0, 4), (dmaSearchParam.get("strtDtD").substr(4, 2) - 1), dmaSearchParam.get("strtDtD").substr(6, 2));
		var mtCnstnLabel = date.getFullYear() + "년" + (date.getMonth() + 1) + "월" + date.getDate() + "일(kWh)";
		date.setDate(date.getDate() - 1);
		var preYyMtCnstnLabel = date.getFullYear() + "년" + (date.getMonth() + 1) + "월" + date.getDate() + "일(kWh)";
	} else {
		var preYyMtCnstnLabel = (Number(dmaSearchParam.get("strtDtM").substr(0, 4)) -1) + "년" + dmaSearchParam.get("strtDtM").substr(4, 2) + "월(kWh)";
		var mtCnstnLabel = dmaSearchParam.get("strtDtM").substr(0, 4) + "년" + dmaSearchParam.get("strtDtM").substr(4, 2) + "월(kWh)";
	}

	var cmmnCd;
	if (id.includes("ChartStdr")) {
		cmmnCd = acbStdrBplc.getValue();
		spnStdrBrffcNm.setValue(" " + acbStdrBplc.selectedItem.text);
	} else if (id.includes("ChartCmpr")) {
		cmmnCd = acbCmprBplc.getValue();
		spnCmprBrffcNm.setValue(" " + acbCmprBplc.selectedItem.text);
	} else {
		return;
	}

	var data = bplcChartList.getAllJSON();

	chartData = data.filter(obj => obj.deptCd == cmmnCd);
	// chartData.forEach(obj => obj.redcnRt = Math.abs(item.redcnRt));

	// 소비 전력량 interval
	var maxMtData = chartData.reduce((max, obj) => Math.max(max, obj.mtCnstn), 0);
	var maxPreMtData = chartData.reduce((max, obj) => Math.max(max, obj.preYyMtCnstn), 0);
	var maxData = maxMtData > maxPreMtData ? maxMtData : maxPreMtData;
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.intervalCount) / chartUnit) * chartUnit;

	// 증감률 interval
	maxData = chartData.reduce((max, obj) => Math.max(max, Math.abs(obj.redcnRt)), 0);
	chartUnit = Math.max(5, Math.pow(5, String(maxData.toFixed(0)).length - 2));
	var rtInterval = Math.ceil((maxData / scwin.initData.chart.intervalCount) / chartUnit) * chartUnit;

	var solidColor1 = ecsLib.getSkinColors().chartSolidColor2;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" borderStyle="none">'
		+ '	<Options>'
	//	+ '		<Caption text="발전원별 생산전력" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '		<Legend defaultMouseOverAction="false" />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+ '	<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="cnstscNm" padding="0.7"/>'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="kWh"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '				<series>'
		+ '					<Column2DSeries yField="preYyMtCnstn" displayName="' + preYyMtCnstnLabel + '">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor1 + '"/>'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '					<Column2DSeries yField="mtCnstn" displayName="' + mtCnstnLabel + '">'
		+ '						<fill>'
		+ '							<SolidColor color="' + solidColor2 + '"/>'
		+ '						</fill>'
		+ '						<showDataEffect>'
		+ '							<SeriesInterpolate />'
		+ '						</showDataEffect>'
		+ '					</Column2DSeries>'
		+ '				</series>'
		+ '			</Column2DSet>'
		+ '			<Line2DSeries yField="redcnRt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="증감률(%)" labelPosition="up"  upLabelJsFunction="' + $p.id + 'scwin.upLabelFontColor">'
		+ '				<stroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</stroke>'
		+ '				<lineStroke>'
		+ '					<Stroke color="#F9BD03" weight="3"/>'
		+ '				</lineStroke>'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxis2" interval="' + rtInterval + '" formatter="{numFmt}" title="%"/>'
		+ '				</verticalAxis>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate/>'
		+ '				</showDataEffect>'
		+ '			</Line2DSeries>'
		+ '		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '			<Axis2DRenderer axis="{vAxis2}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '	</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 차트 라벨 색상 설정
 * @seriesID : seriesID
 * @index : index
 * @data : data
 * @values : values
 */
scwin.upLabelFontColor = function(seriesID, index, data, values) {
	var pre = data.preYyMtCnstn;
	var mt = data.mtCnstn;
	var rt = data.redcnRt;
	var color = "";

	if (pre < mt) {
		color = "red";
	} else if (pre > mt) {
		color = "blue";
	}
	// eles 같거나 0 이라면 default (black)

	return "<font color='" + color + "'>" + data.redcnRt + "</font>";
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnSubTitle.getValue();

	// up, down 기호 제거 _231110
	var grdData = grdEpbuSttusList.getAllDisplayJSON();
	for(var i = 0; i < grdData.length; i++) {
		var currentEqpCcty = grdData[i].eqpCcty;
		var currentThsmonCnsmpElteng = grdData[i].thsmonCnsmpElteng;
		var currentPreYyMtCnsmpElteng = grdData[i].preYyMtCnsmpElteng;
		var currentPrvyySammVersusPwcspDcrsRt = grdData[i].prvyySammVersusPwcspDcrsRt;
		var currentWntyPrvyySammVersusCnsmpRedcnRtRnk = grdData[i].wntyPrvyySammVersusCnsmpRedcnRtRnk;
		var currentBasinPrvyySammVersusCnsmpRedcnRtRnk = grdData[i].basinPrvyySammVersusCnsmpRedcnRtRnk;

		// up 기호 제거
		if (currentEqpCcty.includes("&#9650;&nbsp;") || currentThsmonCnsmpElteng.includes("&#9650;&nbsp;") || currentPreYyMtCnsmpElteng.includes("&#9650;&nbsp;") || currentPrvyySammVersusPwcspDcrsRt.includes("&#9650;&nbsp;")) {
			currentEqpCcty = currentEqpCcty.replace("<span style=\"color:#FF0024;\">&#9650;&nbsp;</span>", "").replace("%", "");
			currentThsmonCnsmpElteng = currentThsmonCnsmpElteng.replace("<span style=\"color:#FF0024;\">&#9650;&nbsp;</span>", "").replace("%", "");
			currentPreYyMtCnsmpElteng = currentPreYyMtCnsmpElteng.replace("<span style=\"color:#FF0024;\">&#9650;&nbsp;</span>", "").replace("%", "");
			currentPrvyySammVersusPwcspDcrsRt = currentPrvyySammVersusPwcspDcrsRt.replace("<span style=\"color:#FF0024;\">&#9650;&nbsp;</span>", "").replace("%", "");
			grdData[i].eqpCcty = currentEqpCcty;
			grdData[i].thsmonCnsmpElteng = currentThsmonCnsmpElteng;
			grdData[i].preYyMtCnsmpElteng = currentPreYyMtCnsmpElteng;
			grdData[i].prvyySammVersusPwcspDcrsRt = currentPrvyySammVersusPwcspDcrsRt;
		}
		// down 기호 제거
		if (currentEqpCcty.includes("&#9660;&nbsp;") || currentThsmonCnsmpElteng.includes("&#9660;&nbsp;") || currentPreYyMtCnsmpElteng.includes("&#9660;&nbsp;") || currentPrvyySammVersusPwcspDcrsRt.includes("&#9660;&nbsp;")) {
			currentEqpCcty = currentEqpCcty.replace("<span style=\"color:#0082FF;\">&#9660;&nbsp;</span>", "").replace("%", "");
			currentThsmonCnsmpElteng = currentThsmonCnsmpElteng.replace("<span style=\"color:#0082FF;\">&#9660;&nbsp;</span>", "").replace("%", "");
			currentPreYyMtCnsmpElteng = currentPreYyMtCnsmpElteng.replace("<span style=\"color:#0082FF;\">&#9660;&nbsp;</span>", "").replace("%", "");
			currentPrvyySammVersusPwcspDcrsRt = currentPrvyySammVersusPwcspDcrsRt.replace("<span style=\"color:#0082FF;\">&#9660;&nbsp;</span>", "").replace("%", "");
			grdData[i].eqpCcty = currentEqpCcty;
			grdData[i].thsmonCnsmpElteng = currentThsmonCnsmpElteng;
			grdData[i].preYyMtCnsmpElteng = currentPreYyMtCnsmpElteng;
			grdData[i].prvyySammVersusPwcspDcrsRt = currentPrvyySammVersusPwcspDcrsRt;
		}
	}
	dltEpbuSttusList.setJSON(grdData, false);

	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 8,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdEpbuSttusList, {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : "true",
		colMerge : "true",
		colMergeValue : "true"
	}, infoArr);

	// 다운로드 후 그리드에 기호 사라지는 거 방지
	scwin.btnInqire_onclick();
};
